import type { Metadata } from "next";
import { Geist, Geist_Mono } from "next/font/google";
import "./globals.css";
import { MqttProvider } from "@/components/MqttProvider";
import { MqttStatusIndicator } from "@/components/MqttStatusIndicator";

const geistSans = Geist({
  variable: "--font-geist-sans",
  subsets: ["latin"],
});

const geistMono = Geist_Mono({
  variable: "--font-geist-mono",
  subsets: ["latin"],
});

export const metadata: Metadata = {
  title: "Emotion Monitoring",
  description: "Sistem pemantauan kesejahteraan user via RFID & Real-time MQTT",
  icons: {
    icon: "/favicon.svg",
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html
      lang="en"
      className={`${geistSans.variable} ${geistMono.variable} h-full antialiased`}
    >
      <body className="min-h-full flex flex-col">
        <MqttProvider>
          {children}
          <MqttStatusIndicator />
        </MqttProvider>
      </body>
    </html>
  );
}
